func solve(s: String) -> Int64 {
    let chars = Array(s)
    let n = chars.count

    // Precompute prefix_L: number of 'L's up to index i (exclusive)
    var prefix_L = [Int64](repeating: 0, count: n + 1)
    for i in 0..<n {
        prefix_L[i+1] = prefix_L[i] + (chars[i] == "L" ? 1 : 0)
    }

    // Precompute suffix_C and suffix_T: number of 'C's and 'T's from index i onwards
    var suffix_C = [Int64](repeating: 0, count: n + 1)
    var suffix_T = [Int64](repeating: 0, count: n + 1)
    for i in (0..<n).reversed() {
        suffix_C[i] = suffix_C[i+1] + (chars[i] == "C" ? 1 : 0)
        suffix_T[i] = suffix_T[i+1] + (chars[i] == "T" ? 1 : 0)
    }

    // Precompute CT_pairs: number of (C, T) pairs starting at or after index i
    var CT_pairs = [Int64](repeating: 0, count: n + 1)
    for i in (0..<n).reversed() {
        if chars[i] == "C" {
            CT_pairs[i] = suffix_T[i+1] + CT_pairs[i+1]
        } else {
            CT_pairs[i] = CT_pairs[i+1]
        }
    }

    // Calculate original count of "LCT" subsequences
    var original_count = 0
    for i in 0..<n {
        if chars[i] == "L" {
            original_count += CT_pairs[i+1]
        }
    }

    // Calculate maximum possible increase from inserting 'L', 'C', or 'T'
    var max_insert_L = 0
    for i in 0...n {
        max_insert_L = max(max_insert_L, CT_pairs[i])
    }

    var max_insert_C = 0
    for i in 0...n {
        let l = prefix_L[i]
        let t = suffix_T[i]
        max_insert_C = max(max_insert_C, l * t)
    }

    var max_insert_T = 0
    for i in 0...n {
